namespace sv_8a3673870d464626b45b63e3361a2dd2.Client.Models;

public sealed class StatusUpdate
{
    public required DateTime Timestamp { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
}

public sealed class ShipmentDetails
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public required DateTime EstimatedDelivery { get; init; }
    public required List<StatusUpdate> Updates { get; init; }
}

using sv_8a3673870d464626b45b63e3361a2dd2.Client.Models;

namespace sv_8a3673870d464626b45b63e3361a2dd2.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net.Http.Json;
using sv_8a3673870d464626b45b63e3361a2dd2.Client.Models;

namespace sv_8a3673870d464626b45b63e3361a2dd2.Client.Services;

public sealed class ShipmentHttpService(HttpClient http) : IShipmentService
{
    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct);
    }
}

using sv_8a3673870d464626b45b63e3361a2dd2.Client.Models;
using sv_8a3673870d464626b45b63e3361a2dd2.Client.Services;

namespace sv_8a3673870d464626b45b63e3361a2dd2.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new ShipmentDetails
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTime(2026, 6, 3, 17, 0, 0, DateTimeKind.Utc),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 27, 8, 0, 0, DateTimeKind.Utc), Status = "Picked Up", Location = "New York, NY" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 28, 6, 30, 0, DateTimeKind.Utc), Status = "In Transit", Location = "Philadelphia, PA" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 29, 2, 15, 0, DateTimeKind.Utc), Status = "In Transit", Location = "Chicago, IL" },
            ]
        },
        ["PKG-002"] = new ShipmentDetails
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTime(2026, 5, 28, 12, 0, 0, DateTimeKind.Utc),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 25, 10, 0, 0, DateTimeKind.Utc), Status = "Picked Up", Location = "Seattle, WA" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 26, 14, 0, 0, DateTimeKind.Utc), Status = "In Transit", Location = "Portland, OR" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 27, 18, 45, 0, DateTimeKind.Utc), Status = "Out for Delivery", Location = "San Francisco, CA" },
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 28, 11, 30, 0, DateTimeKind.Utc), Status = "Delivered", Location = "San Francisco, CA" },
            ]
        },
        ["PKG-003"] = new ShipmentDetails
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTime(2026, 6, 5, 20, 0, 0, DateTimeKind.Utc),
            Updates =
            [
                new StatusUpdate { Timestamp = new DateTime(2026, 5, 29, 0, 10, 0, DateTimeKind.Utc), Status = "Label Created", Location = "Dallas, TX" },
            ]
        },
    };

    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);
        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_8a3673870d464626b45b63e3361a2dd2.Client.Models
@using sv_8a3673870d464626b45b63e3361a2dd2.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IAsyncDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <p><em>Loading shipment @TrackingNumber&hellip;</em></p>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
}
else
{
    <h2>Shipment @_shipment.TrackingNumber</h2>
    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>
        <dt>Current Location</dt>
        <dd>@_shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Tracking History</h3>
    <table class="table">
        <thead>
            <tr>
                <th>Time</th>
                <th>Status</th>
                <th>Location</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var update in _shipment.Updates)
            {
                <tr>
                    <td>@update.Timestamp.ToString("g")</td>
                    <td>@update.Status</td>
                    <td>@update.Location</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter] public string TrackingNumber { get; set; } = default!;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    public override async Task SetParametersAsync(ParameterView parameters)
    {
        var previousTrackingNumber = TrackingNumber;
        await base.SetParametersAsync(parameters);

        if (!string.Equals(previousTrackingNumber, TrackingNumber, StringComparison.Ordinal))
        {
            await LoadShipmentAsync();
        }
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        await CancelPendingRequestAsync();
        _cts = new CancellationTokenSource();

        _loading = true;
        _errorMessage = null;
        _shipment = null;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, _cts.Token);
        }
        catch (OperationCanceledException)
        {
            // Request was cancelled (navigation or dispose); do nothing.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private Task RetryAsync() => LoadShipmentAsync();

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        await CancelPendingRequestAsync();
    }
}

